WITH
RECURSIVE
tree_dept (dept_id,parent_id,ancestors,dept_name,order_num,leader,phone,email,status,del_flag,create_by,create_time,update_by,update_time,dept_name_en) as ( select a.* from sys_dept a where a.dept_id = #{deptId} union all select b.* from tree_dept inner join sys_dept b on tree_dept.dept_id= b.parent_id ) select * from tree_dept where del_flag = '0';

WITH
RECURSIVE
tree_dept (dept_id,parent_id,ancestors,dept_name,order_num,leader,phone,email,status,del_flag,create_by,create_time,update_by,update_time,dept_name_en) as ( select a.* from sys_dept a where a.dept_id = #{deptId} union all select b.* from tree_dept inner join sys_dept b on tree_dept.dept_id= b.parent_id ) select count(*) from tree_dept where status = '0' and del_flag = '0' and dept_id != #{deptId};


